package com.example.rulizormultiplatform.data

import com.example.rulizormultiplatform.data.remote.auth.dto.CheckCodeRequestDto
import com.example.rulizormultiplatform.data.remote.auth.dto.CheckCodeResponseDto
import com.example.rulizormultiplatform.data.remote.auth.dto.LoginRequestDto
import com.example.rulizormultiplatform.data.remote.auth.dto.LoginResponseDto
import com.example.rulizormultiplatform.data.remote.auth.dto.LogoutResponseDto
import com.example.rulizormultiplatform.data.remote.auth.dto.SendCodeRequestDto
import com.example.rulizormultiplatform.data.remote.auth.dto.SendCodeResponseDto
import com.example.rulizormultiplatform.data.remote.base.ApiResponseDto
import com.example.rulizormultiplatform.domain.auth.AuthRepository
import com.example.rulizormultiplatform.domain.auth.TokenStorage
import com.example.rulizormultiplatform.ui.auth.AuthType
import io.ktor.client.HttpClient
import io.ktor.client.call.body
import io.ktor.client.request.header
import io.ktor.client.request.post
import io.ktor.client.request.setBody
import kotlinx.coroutines.flow.first

class KtorAuthRepository(
    private val client: HttpClient,
    private val tokenStorage: TokenStorage
) : AuthRepository {

    override suspend fun sendCode(login: String, authType: AuthType): SendCodeResponseDto {
        val response: ApiResponseDto<SendCodeResponseDto> = client.post("auth/send-code") {
            setBody(
                SendCodeRequestDto(
                    login = login,
                    recaptcha = null,
                    authType = authType.name.lowercase()
                )
            )
        }.body()

        return response.data ?: error(response.message ?: "Empty data")
    }

    override suspend fun checkCode(
        smsToken: String,
        code: String,
        authType: AuthType
    ): CheckCodeResponseDto {
        val response: ApiResponseDto<CheckCodeResponseDto> = client.post("auth/check-code") {
            setBody(
                CheckCodeRequestDto(
                    smsToken = smsToken,
                    code = code,
                    authType = authType.name.lowercase()
                )
            )
        }.body()

        return response.data ?: error(response.message ?: "Empty data")
    }

    override suspend fun login(
        smsToken: String,
        code: String,
        authType: AuthType
    ): LoginResponseDto {
        val response: ApiResponseDto<LoginResponseDto> = client.post("auth/login") {
            setBody(
                LoginRequestDto(
                    smsToken = smsToken,
                    code = code,
                    authType = authType.name.lowercase()
                )
            )
        }.body()

        val data = response.data ?: error(response.message ?: "Empty data")
        tokenStorage.save(data.token)
        return data
    }

    override suspend fun logout(): String {
        val token = tokenStorage.tokenFlow.first()
        val response: ApiResponseDto<LogoutResponseDto> = client.post("auth/logout") {
            if (!token.isNullOrBlank()) {
                header("Authorization", "Bearer $token")
            }
        }.body()

        tokenStorage.clear()
        return response.message ?: "ok"
    }
}

