@Composable
fun AuthScreen(controller: AuthController) {
    val state by controller.state.collectAsState()

    var authType by remember { mutableStateOf(AuthType.EMAIL) }
    var rawInput by remember { mutableStateOf("") } // email as-is, phone as digits only
    var isInputValid by remember { mutableStateOf(true) }

    var code by remember { mutableStateOf("") }
    var smsToken by remember { mutableStateOf("") }
    var codeAuthType by remember { mutableStateOf(AuthType.EMAIL) }
    val isCodeValid = isValidSmsCode(code)
    val canLogin = smsToken.isNotBlank() && isCodeValid

    Column(
        modifier = Modifier
            .fillMaxSize()
            .padding(16.dp),
        horizontalAlignment = Alignment.CenterHorizontally,
    ) {
        Text("Rulizor Auth", style = MaterialTheme.typography.headlineSmall)

        Spacer(modifier = Modifier.height(12.dp))

        Row(verticalAlignment = Alignment.CenterVertically) {
            RadioButton(
                selected = authType == AuthType.PHONE,
                onClick = {
                    authType = AuthType.PHONE
                    rawInput = ""
                    isInputValid = true
                    smsToken = ""
                    code = ""
                }
            )
            Text("Phone")

            Spacer(modifier = Modifier.width(16.dp))

            RadioButton(
                selected = authType == AuthType.EMAIL,
                onClick = {
                    authType = AuthType.EMAIL
                    rawInput = ""
                    isInputValid = true
                    smsToken = ""
                    code = ""
                }
            )
            Text("Email")
        }

        OutlinedTextField(
            value = rawInput,
            onValueChange = { input ->
                if (authType == AuthType.PHONE) {
                    val digits = normalizePhoneDigits(input)
                    rawInput = digits

                    isInputValid = isValidPhoneDigits(digits)
                } else {
                    rawInput = input
                    isInputValid = isValidEmail(input)
                }
            },
            modifier = Modifier
                .fillMaxWidth()
                .padding(top = 16.dp)
                .height(56.dp),
            placeholder = {
                Text(
                    text = if (authType == AuthType.EMAIL) "you@example.com" else "+7(XXX) XXX-XX-XX"
                )
            },
            keyboardOptions = KeyboardOptions(
                keyboardType = if (authType == AuthType.EMAIL) KeyboardType.Email else KeyboardType.Number
            ),
            visualTransformation = if (authType == AuthType.PHONE) PhoneVisualTransformation() else VisualTransformation.None,
            isError = !isInputValid,
            shape = RoundedCornerShape(12.dp)
        )

        if (!isInputValid) {
            Text(
                text = if (authType == AuthType.EMAIL) "Invalid email address" else "Phone must match +7(XXX) XXX-XX-XX",
                color = Color.Red,
                style = MaterialTheme.typography.bodySmall,
                modifier = Modifier.padding(top = 4.dp)
            )
        }

        Button(
            onClick = {
                if (authType == AuthType.PHONE) {
                    controller.sendCodeByPhoneNumber(formatPhone(rawInput))
                } else {
                    controller.sendCodeByEmail(rawInput.trim())
                }
                code = ""
            },
            enabled = isInputValid && rawInput.isNotBlank(),
            modifier = Modifier.padding(top = 8.dp)
        ) {
            Text("Send code")
        }

        if (state is AuthUiState.CodeSent) {
            val sent = state as AuthUiState.CodeSent
            smsToken = sent.smsToken
            codeAuthType = sent.authType
            Text(
                "Code sent (smsToken: ${sent.smsToken})",
                modifier = Modifier.padding(top = 8.dp)
            )
        }

        OutlinedTextField(
            value = code,
            onValueChange = { code = it.filter(Char::isDigit).take(8) },
            label = { Text("Code") },
            keyboardOptions = KeyboardOptions(keyboardType = KeyboardType.Number),
            isError = code.isNotBlank() && !isCodeValid,
            modifier = Modifier
                .fillMaxWidth()
                .padding(top = 16.dp)
        )

        if (code.isNotBlank() && !isCodeValid) {
            Text(
                "Code should contain 4-8 digits",
                color = Color.Red,
                style = MaterialTheme.typography.bodySmall,
                modifier = Modifier.padding(top = 4.dp)
            )
        }

        Button(
            onClick = { controller.login(smsToken, code, codeAuthType) },
            enabled = canLogin,
            modifier = Modifier.padding(top = 8.dp)
        ) {
            Text("Login")
        }

        when (state) {
            is AuthUiState.Loading -> Text("Loading...", modifier = Modifier.padding(top = 16.dp))
            is AuthUiState.Error -> Text(
                "Auth request failed: ${(state as AuthUiState.Error).message}",
                color = Color.Red,
                modifier = Modifier.padding(top = 16.dp)
            )
            is AuthUiState.Authorized -> Text("Authorized", modifier = Modifier.padding(top = 16.dp))
            is AuthUiState.Unauthorized -> Text("Unauthorized", modifier = Modifier.padding(top = 16.dp))
            is AuthUiState.IsNeedRegister -> Text(
                "Need register: ${(state as AuthUiState.IsNeedRegister).isNeedRegister}",
                modifier = Modifier.padding(top = 16.dp)
            )
            else -> Unit
        }
    }
}

class PhoneVisualTransformation : VisualTransformation {

    override fun filter(text: AnnotatedString): TransformedText {
        val digits = text.text.take(10)
        val formatted = formatPhone(digits)

        val offsetMapping = object : OffsetMapping {
            override fun originalToTransformed(offset: Int): Int {
                return when {
                    offset <= 0 -> 2
                    offset <= 3 -> offset + 3
                    offset <= 6 -> offset + 5
                    offset <= 8 -> offset + 6
                    offset <= 10 -> offset + 7
                    else -> formatted.length
                }.coerceAtMost(formatted.length)
            }

            override fun transformedToOriginal(offset: Int): Int {
                return when {
                    offset <= 2 -> 0
                    offset <= 6 -> offset - 3
                    offset <= 11 -> offset - 5
                    offset <= 14 -> offset - 6
                    offset <= 17 -> offset - 7
                    else -> digits.length
                }.coerceIn(0, digits.length)
            }
        }

        return TransformedText(
            AnnotatedString(formatted),
            offsetMapping
        )
    }
}

