package com.example.rulizormultiplatform.ui.auth

import com.example.rulizormultiplatform.domain.auth.AuthRepository
import kotlinx.coroutines.CoroutineScope
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.launch

class AuthController(
    private val repository: AuthRepository,
    private val scope: CoroutineScope,
) {

    private val _state = MutableStateFlow<AuthUiState>(AuthUiState.Idle)
    val state: StateFlow<AuthUiState> = _state

    fun sendCodeByEmail(email: String) {
        scope.launch {
            _state.value = AuthUiState.Loading
            runCatching { repository.sendCode(email, AuthType.EMAIL) }
                .onSuccess { _state.value = AuthUiState.CodeSent(it.smsToken, AuthType.EMAIL) }
                .onFailure { _state.value = AuthUiState.Error(buildErrorMessage("send code by email", it)) }
        }
    }

    fun sendCodeByPhoneNumber(telephoneNumber: String) {
        scope.launch {
            _state.value = AuthUiState.Loading
            runCatching { repository.sendCode(telephoneNumber, AuthType.PHONE) }
                .onSuccess { _state.value = AuthUiState.CodeSent(it.smsToken, AuthType.PHONE) }
                .onFailure { _state.value = AuthUiState.Error(buildErrorMessage("send code by phone", it)) }
        }
    }

    fun checkCode(smsToken: String, code: String, authType: AuthType) {
        scope.launch {
            _state.value = AuthUiState.Loading
            runCatching { repository.checkCode(smsToken, code, authType) }
                .onSuccess { _state.value = AuthUiState.IsNeedRegister(it.isNeedRegister) }
                .onFailure { _state.value = AuthUiState.Error(buildErrorMessage("check code", it)) }
        }
    }

    fun login(smsToken: String, code: String, authType: AuthType) {
        scope.launch {
            _state.value = AuthUiState.Loading
            runCatching { repository.login(smsToken, code, authType) }
                .onSuccess {
                    // Platform-specific code can observe token changes and
                    // update state to Authorized when appropriate.
                }
                .onFailure { _state.value = AuthUiState.Error(buildErrorMessage("login", it)) }
        }
    }

    fun logout() {
        scope.launch {
            _state.value = AuthUiState.Loading
            runCatching { repository.logout() }
                .onSuccess { _state.value = AuthUiState.Unauthorized }
                .onFailure { _state.value = AuthUiState.Error(buildErrorMessage("logout", it)) }
        }
    }

    private fun buildErrorMessage(action: String, throwable: Throwable): String {
        val details = throwable.message?.takeIf { it.isNotBlank() } ?: "Unknown error"
        return "$action failed: $details"
    }
}

