package com.example.rulizormultiplatform.ui.auth

sealed interface AuthUiState {
    data object Idle : AuthUiState
    data object Loading : AuthUiState
    data class CodeSent(val smsToken: String, val authType: AuthType) : AuthUiState
    data class IsNeedRegister(val isNeedRegister: Boolean) : AuthUiState
    data object Authorized : AuthUiState
    data object Unauthorized : AuthUiState
    data class Error(val message: String) : AuthUiState
}

