package com.example.rulizormultiplatform

import androidx.compose.runtime.remember
import androidx.compose.runtime.rememberCoroutineScope
import androidx.compose.ui.ExperimentalComposeUiApi
import androidx.compose.ui.window.ComposeViewport
import com.example.rulizormultiplatform.di.WebAuthCompositionRoot
import com.example.rulizormultiplatform.ui.auth.AuthScreen
import kotlinx.browser.document

@OptIn(ExperimentalComposeUiApi::class)
fun main() {
    document.body?.classList?.add("app-ready")
    document.getElementById("loader")?.remove()

    ComposeViewport {
        val scope = rememberCoroutineScope()
        val controller = remember {
            WebAuthCompositionRoot().createAuthController(scope)
        }
        AuthScreen(controller)
    }
}

