package com.example.rulizormultiplatform.di

import com.example.rulizormultiplatform.data.KtorAuthRepository
import com.example.rulizormultiplatform.data.KtorUserRepository
import com.example.rulizormultiplatform.data.datastore.InMemoryTokenStorage
import com.example.rulizormultiplatform.ui.auth.AuthController
import com.example.rulizormultiplatform.ui.user.ProfileController
import io.ktor.client.HttpClient
import io.ktor.client.engine.js.Js
import io.ktor.client.plugins.contentnegotiation.ContentNegotiation
import io.ktor.client.plugins.defaultRequest
import io.ktor.http.ContentType
import io.ktor.http.contentType
import io.ktor.serialization.kotlinx.json.json
import kotlinx.coroutines.CoroutineScope
import kotlinx.serialization.json.Json

class WebAuthCompositionRoot {
    private val tokenStorage = InMemoryTokenStorage()
    private val httpClient = HttpClient(Js) {
        defaultRequest {
            url("https://api.rulizor.ru/api/")
            contentType(ContentType.Application.Json)
        }
        install(ContentNegotiation) {
            json(
                Json {
                    ignoreUnknownKeys = true
                    explicitNulls = false
                }
            )
        }
    }

    fun createAuthController(scope: CoroutineScope): AuthController {
        return AuthController(
            repository = KtorAuthRepository(httpClient, tokenStorage),
            scope = scope
        )
    }

    fun createProfileController(scope: CoroutineScope): ProfileController {
        return ProfileController(
            repository = KtorUserRepository(httpClient, tokenStorage),
            scope = scope
        )
    }
}

