package com.example.rulizormultiplatform.ui.auth

private val phoneRegex = Regex("""^\+7\(\d{3}\) \d{3}-\d{2}-\d{2}$""")
private val emailRegex = Regex("^[A-Za-z0-9+_.-]+@[A-Za-z0-9.-]+$")
private val codeRegex = Regex("""^\d{4,8}$""")

fun normalizePhoneDigits(input: String): String = input.filter { it.isDigit() }.take(10)

fun formatPhone(digits: String): String {
    return buildString {
        append("+7")

        if (digits.isNotEmpty()) {
            append("(")
            append(digits.take(3))
        }
        if (digits.length >= 3) {
            append(") ")
            append(digits.drop(3).take(3))
        }
        if (digits.length >= 6) {
            append("-")
            append(digits.drop(6).take(2))
        }
        if (digits.length >= 8) {
            append("-")
            append(digits.drop(8).take(2))
        }
    }
}

fun isValidPhoneDigits(digits: String): Boolean = phoneRegex.matches(formatPhone(digits))

fun isValidEmail(email: String): Boolean = emailRegex.matches(email.trim())

fun isValidSmsCode(code: String): Boolean = codeRegex.matches(code.trim())

