package com.example.rulizormultiplatform.data.remote.auth.dto

import kotlinx.serialization.Serializable

@Serializable
data class SendCodeRequestDto(
    val login: String,
    val recaptcha: String? = null,
    val authType: String = "email"
)

@Serializable
data class LoginRequestDto(
    val smsToken: String,
    val code: String,
    var role: String = "expert",
    var authType: String = "email"
)

@Serializable
data class CheckCodeRequestDto(
    val smsToken: String,
    val code: String,
    var role: String = "expert",
    var authType: String = "email"
)

@Serializable
data class SendCodeResponseDto(
    val status: String,
    val authType: String,
    val expiredAt: String,
    val smsToken: String
)

@Serializable
data class CheckCodeResponseDto(
    val isNeedRegister: Boolean
)

@Serializable
data class LoginResponseDto(
    val token: String
)

@Serializable
data class LogoutResponseDto(
    val data: String? = null
)

